    36	TranslationUnit*
    37	Ast2Asg::operator()(ast::TranslationUnitContext* ctx)
    38	{
    39	  auto ret = make<asg::TranslationUnit>();
    40	  if (ctx == nullptr)
    41	    return ret;
    42	
    43	  Symtbl localDecls(self);
    44	
    45	  for (auto&& i : ctx->externalDeclaration()) {
    46	    if (auto p = i->declaration()) {
    47	      auto decls = self(p);
    48	      ret->decls.insert(ret->decls.end(),
    49	                        std::make_move_iterator(decls.begin()),
    50	                        std::make_move_iterator(decls.end()));
    51	    }
    52	
    53	    else if (auto p = i->functionDefinition()) {
    54	      auto funcDecl = self(p);
    55	      ret->decls.push_back(funcDecl);
    56	
    57	      // 添加到声明表
    58	      localDecls[funcDecl->name] = funcDecl;
    59	    }
    60	
    61	    else
    62	      ABORT();
    63	  }
    64	
    65	  return ret;
    66	}
